import { WebhookClient } from "discord.js";

export interface ErrorHandlingConfig {
  embedColor?: string;
  embedTitle?: string;
  webhookUsername?: string;
  embedAvatarUrl?: string;
  errorLog?: boolean;
  warningLog?: boolean;
  infoLog?: boolean;
  webhookUrl: string;
}

export interface ErrorHandling {
  errorHandling(client: any, config?: ErrorHandlingConfig): Promise<void>;
}

export const errorHandling: ErrorHandling['errorHandling'];

// Custom error types
export class CustomError extends Error {
  constructor(message: string, public code?: number);
}

// Custom log types
export const log: {
  error: (error: Error | string, details?: string) => void;
  warning: (warning: string, details?: string) => void;
  info: (info: string) => void;
};
